import MetricCard from "../../../components/dashboard/MetricCard";
import { IconBookmark, IconBriefcase, IconEye, IconFile } from "../../../components/dashboard/icons";
import { MOCK_JOBS } from "../../../data/mockData";

const NOTIFICATIONS = [
  { icon: "📷", text: "Add a profile photo to improve visibility", time: "2 days ago" },
  { icon: "✓", text: "Welcome! Complete your profile to 70% to apply for jobs.", time: "1 week ago" },
];

export default function TeacherOverview({ user, setPage, setTab, applications, savedCount, profilePercent = 0 }) {
  const showSuggested = profilePercent >= 70;

  return (
    <>
      <h1 className="portal-page-title">Dashboard</h1>
      <div className="metric-row">
        <MetricCard label="Saved Jobs" value={savedCount} variant="blue" icon={<IconBookmark />} />
        <MetricCard label="Applied Jobs" value={applications.length} variant="navy" icon={<IconFile />} />
        <MetricCard label="Profile Views" value="28" variant="green" icon={<IconEye />} />
        <MetricCard label="Profile Complete" value={`${profilePercent}%`} variant="orange" icon={<IconBriefcase />} />
      </div>

      <div className="portal-widgets">
        <div className="portal-widgets__left">
          <div className="widget-card">
            <div className="widget-card__head">
              <h2 className="widget-card__title">Suggested Jobs</h2>
            </div>
            {!showSuggested ? (
              <div className="widget-empty">
                <div className="widget-empty__icon">💼</div>
                <p className="widget-empty__text">
                  Complete your profile to <strong>70%</strong> to see suggested jobs matched to your skills.
                </p>
                <button type="button" className="btn btn-primary" onClick={() => setTab("profile")}>
                  Complete Profile
                </button>
              </div>
            ) : (
              <div className="job-list">
                {MOCK_JOBS.slice(0, 3).map((j) => (
                  <div key={j.id} className="job-list__item">
                    <div className="jlogo">{j.logo}</div>
                    <div className="job-list__body">
                      <div className="job-list__title">{j.title}</div>
                      <div className="job-list__company">{j.institute}</div>
                      <div className="job-list__meta">{j.location} · {j.posted}</div>
                    </div>
                    <button type="button" className="btn btn-primary btn-sm" onClick={() => setPage("jobs")}>Apply</button>
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="widget-card">
            <div className="widget-card__head">
              <h2 className="widget-card__title">My Applications</h2>
              <button type="button" className="widget-card__link" onClick={() => setTab("applied")}>View all</button>
            </div>
            <div className="app-list">
              {applications.map((a, i) => (
                <div key={i} className="app-list__item">
                  <div>
                    <div className="app-list__title">{a.job}</div>
                    <div className="app-list__meta">{a.school} · Applied {a.ago}</div>
                  </div>
                  <span className={`badge ${a.color}`}>{a.status}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="portal-widgets__right">
          <div className="widget-card">
            <div className="widget-card__head">
              <h2 className="widget-card__title">Recent Jobs</h2>
              <button type="button" className="widget-card__link" onClick={() => setPage("jobs")}>Browse all</button>
            </div>
            <div className="job-list job-list--compact">
              {MOCK_JOBS.slice(0, 5).map((j) => (
                <div key={j.id} className="job-list__item job-list__item--clickable" onClick={() => setPage("jobs")}>
                  <div className="jlogo jlogo--sm">{j.logo}</div>
                  <div className="job-list__body">
                    <div className="job-list__title">{j.title}</div>
                    <div className="job-list__company">{j.institute}</div>
                    <div className="job-list__meta">{j.location} · {j.posted}</div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="widget-card">
            <div className="widget-card__head">
              <h2 className="widget-card__title">Notifications</h2>
            </div>
            <div className="notif-list">
              {NOTIFICATIONS.map((n, i) => (
                <div key={i} className="notif-list__item">
                  <span className="notif-list__icon">{n.icon}</span>
                  <div>
                    <div className="notif-list__text">{n.text}</div>
                    <div className="notif-list__time">{n.time}</div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </>
  );
}
