import { useEffect, useState } from "react";
import JobCard from "../components/jobs/JobCard";
import Modal from "../components/ui/Modal";
import Spinner from "../components/ui/Spinner";
import { useAuth } from "../context/AuthContext";
import { applicationsAPI, jobsAPI } from "../api";

export default function JobsPage({ setPage }) {
  const { user } = useAuth();
  const [filter, setFilter] = useState({ subject: "", type: "", location: "", search: "" });
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedJob, setSelectedJob] = useState(null);
  const [applied, setApplied] = useState([]);
  const [loginAlert, setLoginAlert] = useState(false);
  const [applyErr, setApplyErr] = useState("");
  const [applying, setApplying] = useState(false);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    jobsAPI
      .getAll(filter)
      .then((data) => { if (!cancelled) setJobs(data); })
      .catch(() => { if (!cancelled) setJobs([]); })
      .finally(() => { if (!cancelled) setLoading(false); });
    return () => { cancelled = true; };
  }, [filter.subject, filter.type, filter.location, filter.search]);

  useEffect(() => {
    if (!user || (user.role !== "teacher" && user.role !== "tutor")) return;
    applicationsAPI
      .myApplications()
      .then((apps) => setApplied(apps.map((a) => a.job_id)))
      .catch(() => {});
  }, [user]);

  async function handleApply(job) {
    if (!user) {
      setLoginAlert(true);
      return;
    }
    if (user.role !== "teacher" && user.role !== "tutor") {
      alert("Only teachers and tutors can apply to jobs.");
      return;
    }
    if (applied.includes(job.id)) {
      setSelectedJob(job);
      return;
    }
    setApplyErr("");
    setApplying(true);
    try {
      await applicationsAPI.apply({ job_id: job.id });
      setApplied((a) => [...a, job.id]);
      setSelectedJob(job);
    } catch (ex) {
      setApplyErr(ex.message);
      if (ex.message.includes("resume") || ex.message.includes("profile")) {
        setPage("dashboard");
      }
    }
    setApplying(false);
  }

  return (
    <div style={{ paddingTop: 72 }}>
      <div className="page-header">
        <div className="container">
          <h1 className="page-title">Browse Teaching Jobs</h1>
          <p className="page-desc">Discover opportunities across India's best schools and institutions</p>
          <div style={{ display: "flex", gap: 12, paddingBottom: 24, flexWrap: "wrap" }}>
            <input
              className="input"
              style={{ maxWidth: 220 }}
              placeholder="Search jobs..."
              value={filter.search}
              onChange={(e) => setFilter({ ...filter, search: e.target.value })}
            />
            <input
              className="input"
              style={{ maxWidth: 180 }}
              placeholder="Subject..."
              value={filter.subject}
              onChange={(e) => setFilter({ ...filter, subject: e.target.value })}
            />
            <select
              className="input"
              style={{ maxWidth: 160 }}
              value={filter.type}
              onChange={(e) => setFilter({ ...filter, type: e.target.value })}
            >
              <option value="">All Types</option>
              <option>Full-Time</option>
              <option>Part-Time</option>
              <option>Home Tuition</option>
            </select>
            <input
              className="input"
              style={{ maxWidth: 180 }}
              placeholder="Location..."
              value={filter.location}
              onChange={(e) => setFilter({ ...filter, location: e.target.value })}
            />
          </div>
        </div>
      </div>

      <div className="container" style={{ paddingTop: 36, paddingBottom: 72 }}>
        {loginAlert && (
          <div className="alert a-err flexb" style={{ marginBottom: 24 }}>
            <span>Please login as a Teacher or Tutor to apply for jobs.</span>
            <button className="btn btn-primary btn-sm" onClick={() => setPage("login")}>Login Now</button>
          </div>
        )}
        {applyErr && <div className="alert a-err" style={{ marginBottom: 24 }}>{applyErr}</div>}
        <div style={{ marginBottom: 20, color: "var(--muted)", fontSize: 14 }}>
          Showing <strong style={{ color: "var(--text)" }}>{jobs.length}</strong> jobs
        </div>
        {loading ? (
          <div style={{ textAlign: "center", padding: 60 }}><Spinner /></div>
        ) : (
          <div className="grid3">
            {jobs.map((job) => (
              <div key={job.id}>
                <JobCard job={job} onApply={handleApply} />
                {applied.includes(job.id) && (
                  <div style={{ textAlign: "center", marginTop: 8 }}>
                    <span className="badge bgreen">Applied</span>
                  </div>
                )}
              </div>
            ))}
            {jobs.length === 0 && (
              <div style={{ gridColumn: "1/-1", textAlign: "center", padding: "60px 0" }}>
                <h3 style={{ marginBottom: 8 }}>No jobs found</h3>
                <p style={{ color: "var(--muted)" }}>Try adjusting your filters or check back later</p>
              </div>
            )}
          </div>
        )}
      </div>

      <Modal open={!!selectedJob} onClose={() => setSelectedJob(null)}>
        {selectedJob && (
          <>
            <div className="flexb" style={{ marginBottom: 20 }}>
              <div className="jlogo" style={{ width: 56, height: 56, fontSize: 26 }}>🏫</div>
              <span className="badge bgreen">Applied</span>
            </div>
            <h2 style={{ fontSize: 22, marginBottom: 6 }}>{selectedJob.title}</h2>
            <div style={{ color: "var(--accent)", fontWeight: 600, marginBottom: 18, fontSize: 14 }}>
              {selectedJob.institute_name || selectedJob.institute}
            </div>
            <div className="alert a-ok">
              Your application has been submitted. The school will review your profile and contact you soon.
            </div>
            <div style={{ display: "flex", gap: 12, marginTop: 24 }}>
              <button className="btn btn-primary" style={{ flex: 1 }} onClick={() => { setSelectedJob(null); setPage("dashboard"); }}>
                View in Dashboard
              </button>
              <button className="btn btn-outline" style={{ flex: 1 }} onClick={() => setSelectedJob(null)}>Close</button>
            </div>
          </>
        )}
      </Modal>
      {applying && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.2)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 999 }}>
          <Spinner />
        </div>
      )}
    </div>
  );
}
