import { useState } from "react";
import { useAuth } from "../../context/AuthContext";
import { IconBell } from "./icons";
import Avatar from "./Avatar";

export default function DashboardTopNav({ setPage, active = "dashboard" }) {
  const { user, logout } = useAuth();
  const [menuOpen, setMenuOpen] = useState(false);

  const links = [
    { id: "dashboard", label: "Dashboard" },
    { id: "jobs", label: "Jobs" },
    { id: "schools", label: "Schools / Institutes" },
    { id: "faq", label: "FAQ" },
  ];

  function go(id) {
    if (id === "dashboard") setPage("dashboard");
    else if (id === "jobs") setPage("jobs");
    else if (id === "schools") setPage("institutes");
    else if (id === "faq") setPage("faq");
    else setPage("home");
    setMenuOpen(false);
  }

  return (
    <header className="portal-topnav">
      <div className="portal-topnav__brand" onClick={() => setPage("home")}>
        EduHire
      </div>
      <nav className="portal-topnav__links">
        {links.map((l) => (
          <button
            key={l.id}
            type="button"
            className={`portal-topnav__link ${active === l.id ? "active" : ""}`}
            onClick={() => go(l.id)}
          >
            {l.label}
          </button>
        ))}
      </nav>
      <div className="portal-topnav__actions">
        <button type="button" className="portal-notif" aria-label="Notifications">
          <IconBell />
          <span className="portal-notif__badge">1</span>
        </button>
        <div className="portal-user-menu">
          <button
            type="button"
            className="portal-user-menu__trigger"
            onClick={() => setMenuOpen((o) => !o)}
          >
            <Avatar name={user?.name || "User"} size={36} round />
            <span className="portal-user-menu__name">{user?.name?.split(" ")[0]}</span>
            <span className="portal-user-menu__caret">▾</span>
          </button>
          {menuOpen && (
            <div className="portal-dropdown">
              <button type="button" onClick={() => { setPage("dashboard"); setMenuOpen(false); }}>My Dashboard</button>
              <button type="button" onClick={() => { setPage("dashboard"); setMenuOpen(false); }}>My Profile</button>
              <button type="button" className="danger" onClick={logout}>Logout</button>
            </div>
          )}
        </div>
      </div>
    </header>
  );
}
