import { useEffect, useState } from "react";
import Avatar from "../../components/dashboard/Avatar";
import DataTable from "../../components/dashboard/DataTable";
import MetricCard from "../../components/dashboard/MetricCard";
import Modal from "../../components/ui/Modal";
import PortalLayout from "../../components/dashboard/PortalLayout";
import FormSection from "../../components/portal/FormSection";
import { IconBriefcase, IconFile, IconSearch, IconUser } from "../../components/dashboard/icons";
import { schoolMenu } from "../../data/portalMenus";
import { SUBJECTS } from "../../data/mockData";
import { applicationsAPI, jobsAPI, profileAPI, resumeUrl } from "../../api";

function timeAgo(dateStr) {
  if (!dateStr) return "Recently";
  const d = new Date(dateStr);
  const days = Math.floor((Date.now() - d) / 86400000);
  if (days < 1) return "Today";
  if (days === 1) return "1 day ago";
  return `${days} days ago`;
}

export default function SchoolDashboard({ user, setPage, onRefresh }) {
  const [tab, setTab] = useState("overview");
  const [showPost, setShowPost] = useState(false);
  const [toast, setToast] = useState("");
  const [form, setForm] = useState({ title: "", subject: "", type: "Full-Time", location: "", description: "" });
  const [myJobs, setMyJobs] = useState([]);
  const [applicants, setApplicants] = useState([]);
  const [profileForm, setProfileForm] = useState({
    institute_name: user.profile?.institute_name || user.name,
    institute_type: user.profile?.institute_type || "",
    description: user.profile?.description || "",
    contact_person: user.profile?.contact_person || "",
    website: user.profile?.website || "",
    phone: user.phone || "",
    city: user.city || "",
  });

  const approval = user.approvalStatus || user.profile?.approval_status || "pending";
  const canPost = user.canPostJobs;
  const profilePct = user.profileComplete || 0;

  const showToastMsg = (m) => { setToast(m); setTimeout(() => setToast(""), 3000); };
  const up = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  async function loadJobs() {
    try {
      const jobs = await jobsAPI.getMyJobs();
      setMyJobs(jobs);
      if (jobs.length) {
        const apps = await applicationsAPI.getApplicants(jobs[0].id);
        setApplicants(apps);
      }
    } catch {}
  }

  useEffect(() => { loadJobs(); }, []);

  async function postJob(e) {
    e.preventDefault();
    if (!canPost) {
      showToastMsg("Your institute must be approved by admin before posting jobs.");
      return;
    }
    try {
      await jobsAPI.post({
        title: form.title,
        subject: form.subject,
        job_type: form.type,
        location: form.location,
        description: form.description,
      });
      setShowPost(false);
      setForm({ title: "", subject: "", type: "Full-Time", location: "", description: "" });
      showToastMsg("Job submitted for admin review.");
      loadJobs();
    } catch (ex) {
      showToastMsg(ex.message);
    }
  }

  async function saveProfile() {
    try {
      await profileAPI.updateSchool(profileForm);
      showToastMsg("Profile saved.");
      onRefresh?.();
    } catch (ex) {
      showToastMsg(ex.message);
    }
  }

  async function updateAppStatus(id, status) {
    try {
      await applicationsAPI.updateStatus(id, status);
      showToastMsg("Application updated.");
      loadJobs();
    } catch (ex) {
      showToastMsg(ex.message);
    }
  }

  const activeCount = myJobs.filter((j) => j.status === "approved").length;
  const menu = schoolMenu(tab, { jobs: myJobs.length, applications: applicants.length });

  return (
    <PortalLayout
      user={user}
      setPage={setPage}
      menu={menu}
      onNavigate={(m) => setTab(m.id)}
      onViewProfile={() => setTab("profile")}
      profilePercent={profilePct}
      toast={toast}
      showReferral={false}
    >
      {approval !== "approved" && (
        <div className={`alert ${approval === "rejected" ? "a-err" : "a-warn"}`} style={{ marginBottom: 20 }}>
          {approval === "pending"
            ? "Your institute is awaiting admin approval. You cannot post jobs until approved."
            : "Your institute was not approved. Contact admin or update your profile."}
        </div>
      )}

      {tab === "overview" && (
        <>
          <div className="flexb" style={{ marginBottom: 4 }}>
            <h1 className="portal-page-title" style={{ marginBottom: 0 }}>Dashboard</h1>
            <button type="button" className="btn btn-primary" onClick={() => setShowPost(true)} disabled={!canPost}>+ Post New Job</button>
          </div>
          <div className="metric-row">
            <MetricCard label="Active Jobs" value={activeCount} variant="blue" icon={<IconBriefcase />} />
            <MetricCard label="Applications" value={applicants.length} variant="navy" icon={<IconFile />} />
            <MetricCard label="Pending Jobs" value={myJobs.filter((j) => j.status === "pending").length} variant="orange" icon={<IconBriefcase />} />
            <MetricCard label="Profile Complete" value={`${profilePct}%`} variant="green" icon={<IconUser />} />
          </div>
          <div className="portal-widgets" style={{ gridTemplateColumns: "1fr 380px" }}>
            <div className="widget-card">
              <div className="widget-card__head">
                <h2 className="widget-card__title">Recent Job Posts</h2>
                <button type="button" className="widget-card__link" onClick={() => setTab("jobs")}>View all</button>
              </div>
              {myJobs.map((j, i) => (
                <div key={j.id} className="app-list__item" style={{ borderBottom: i < myJobs.length - 1 ? "1px solid var(--border)" : "none" }}>
                  <div>
                    <div className="app-list__title">{j.title}</div>
                    <div className="app-list__meta">Posted {timeAgo(j.created_at)} · {j.applicant_count || 0} applicants</div>
                  </div>
                  <span className={`badge ${j.status === "approved" ? "bgreen" : j.status === "rejected" ? "bred" : "byellow"}`}>
                    {j.status === "approved" ? "Live" : j.status}
                  </span>
                </div>
              ))}
              {myJobs.length === 0 && <p className="widget-empty__text">No jobs posted yet.</p>}
            </div>
            <div className="widget-card">
              <div className="widget-card__head"><h2 className="widget-card__title">Recent Applications</h2></div>
              {applicants.slice(0, 3).map((a, i) => (
                <div key={a.id} className="app-list__item" style={{ borderBottom: i < 2 ? "1px solid var(--border)" : "none" }}>
                  <div>
                    <div className="app-list__title">{a.teacher_name}</div>
                    <div className="app-list__meta">{a.subject} · {a.experience}</div>
                  </div>
                  <span className={`badge ${a.status === "shortlisted" ? "bgreen" : a.status === "rejected" ? "bred" : "byellow"}`}>{a.status}</span>
                </div>
              ))}
              {applicants.length === 0 && <p className="widget-empty__text">No applications yet.</p>}
              <button type="button" className="btn btn-outline btn-sm" style={{ marginTop: 12 }} onClick={() => setTab("applications")}>Manage Applications</button>
            </div>
          </div>
        </>
      )}

      {tab === "jobs" && (
        <>
          <div className="flexb">
            <h1 className="portal-page-title">My Job Posts</h1>
            <button type="button" className="btn btn-primary" onClick={() => setShowPost(true)} disabled={!canPost}>+ Post New Job</button>
          </div>
          <p className="portal-page-desc">Publish openings and manage listings</p>
          <DataTable columns={["Job Title", "Posted", "Applicants", "Status", "Action"]}>
            {myJobs.map((j) => (
              <tr key={j.id}>
                <td><strong>{j.title}</strong></td>
                <td style={{ color: "var(--muted)" }}>{timeAgo(j.created_at)}</td>
                <td>{j.applicant_count || 0}</td>
                <td><span className={`badge ${j.status === "approved" ? "bgreen" : j.status === "rejected" ? "bred" : "byellow"}`}>{j.status === "approved" ? "Live" : j.status}</span></td>
                <td><button type="button" className="btn btn-outline btn-sm" onClick={async () => { const apps = await applicationsAPI.getApplicants(j.id); setApplicants(apps); setTab("applications"); }}>Applicants</button></td>
              </tr>
            ))}
          </DataTable>
        </>
      )}

      {tab === "applications" && (
        <>
          <h1 className="portal-page-title">Applications</h1>
          <p className="portal-page-desc">Review, shortlist, or reject teacher applications</p>
          <DataTable columns={["Teacher", "Subject", "Experience", "Resume", "Status", "Actions"]}>
            {applicants.map((a) => (
              <tr key={a.id}>
                <td><div className="table-cell-user"><Avatar name={a.teacher_name} size={36} round /><strong>{a.teacher_name}</strong></div></td>
                <td>{a.subject || "—"}</td>
                <td>{a.experience || "—"}</td>
                <td>{a.resume_url ? <a href={resumeUrl(a.resume_url)} target="_blank" rel="noreferrer" className="widget-card__link">View</a> : "—"}</td>
                <td><span className={`badge ${a.status === "shortlisted" ? "bgreen" : a.status === "rejected" ? "bred" : "byellow"}`}>{a.status}</span></td>
                <td>
                  <div className="table-actions">
                    <button type="button" className="btn btn-success btn-sm" onClick={() => updateAppStatus(a.id, "shortlisted")}>Shortlist</button>
                    <button type="button" className="btn btn-danger btn-sm" onClick={() => updateAppStatus(a.id, "rejected")}>Reject</button>
                  </div>
                </td>
              </tr>
            ))}
          </DataTable>
          {applicants.length === 0 && <p style={{ color: "var(--muted)", marginTop: 16 }}>Select a job with applicants or post a job first.</p>}
        </>
      )}

      {tab === "search" && (
        <>
          <h1 className="portal-page-title">Search Educators</h1>
          <p className="portal-page-desc">Browse applicants from your job posts</p>
          <p style={{ color: "var(--muted)" }}>Use the Applications tab to review teachers who applied to your jobs.</p>
        </>
      )}

      {tab === "profile" && (
        <>
          <h1 className="portal-page-title">Institute Profile</h1>
          <FormSection title="School / Institution Details">
            <div className="grid2">
              <div className="fg"><label className="flabel">Institute Name</label><input className="input" value={profileForm.institute_name} onChange={(e) => setProfileForm((f) => ({ ...f, institute_name: e.target.value }))} /></div>
              <div className="fg"><label className="flabel">Institute Type</label><input className="input" value={profileForm.institute_type} onChange={(e) => setProfileForm((f) => ({ ...f, institute_type: e.target.value }))} /></div>
              <div className="fg"><label className="flabel">City</label><input className="input" value={profileForm.city} onChange={(e) => setProfileForm((f) => ({ ...f, city: e.target.value }))} /></div>
              <div className="fg"><label className="flabel">Phone</label><input className="input" value={profileForm.phone} onChange={(e) => setProfileForm((f) => ({ ...f, phone: e.target.value }))} /></div>
              <div className="fg"><label className="flabel">Website</label><input className="input" value={profileForm.website} onChange={(e) => setProfileForm((f) => ({ ...f, website: e.target.value }))} /></div>
              <div className="fg"><label className="flabel">Contact Person</label><input className="input" value={profileForm.contact_person} onChange={(e) => setProfileForm((f) => ({ ...f, contact_person: e.target.value }))} /></div>
            </div>
            <div className="fg"><label className="flabel">About Institute</label><textarea className="input" rows={4} value={profileForm.description} onChange={(e) => setProfileForm((f) => ({ ...f, description: e.target.value }))} /></div>
            <button type="button" className="btn btn-primary" onClick={saveProfile}>Save Profile</button>
          </FormSection>
        </>
      )}

      {tab === "admission" && (
        <>
          <h1 className="portal-page-title">Admission Inquiry</h1>
          <p className="portal-page-desc">Coming soon — manage admission inquiries from your public profile</p>
        </>
      )}

      {tab === "security" && (
        <>
          <h1 className="portal-page-title">Security</h1>
          <FormSection title="Account">
            <div className="fg"><label className="flabel">Email</label><input className="input" value={user.email} disabled /></div>
          </FormSection>
        </>
      )}

      <Modal open={showPost} onClose={() => setShowPost(false)} wide>
        <h2 style={{ fontSize: 22, marginBottom: 16 }}>Post a New Job</h2>
        <div className="alert a-warn">Jobs are reviewed by admin before going live.</div>
        <form onSubmit={postJob}>
          <div className="fg"><label className="flabel">Job Title *</label><input className="input" value={form.title} onChange={(e) => up("title", e.target.value)} required /></div>
          <div className="grid2">
            <div className="fg"><label className="flabel">Subject *</label><select className="input" value={form.subject} onChange={(e) => up("subject", e.target.value)} required><option value="">Select</option>{SUBJECTS.map((s) => <option key={s}>{s}</option>)}</select></div>
            <div className="fg"><label className="flabel">Job Type</label><select className="input" value={form.type} onChange={(e) => up("type", e.target.value)}><option>Full-Time</option><option>Part-Time</option><option>Home Tuition</option></select></div>
          </div>
          <div className="fg"><label className="flabel">Location</label><input className="input" value={form.location} onChange={(e) => up("location", e.target.value)} /></div>
          <div className="fg"><label className="flabel">Description</label><textarea className="input" rows={4} value={form.description} onChange={(e) => up("description", e.target.value)} /></div>
          <button type="submit" className="btn btn-primary" style={{ width: "100%" }} disabled={!canPost}>Submit for Review</button>
        </form>
      </Modal>
    </PortalLayout>
  );
}
