import { useState } from "react";
import FormSection from "../../../components/portal/FormSection";
import Avatar from "../../../components/dashboard/Avatar";
import { SUBJECTS, EXPERIENCE_LEVELS, QUALIFICATIONS } from "../../../data/mockData";
import { profileAPI } from "../../../api";

export default function TeacherProfile({ user, profile, setProfile, editMode, setEditMode, profilePercent, role, onRefresh }) {
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState("");

  async function save() {
    setSaving(true);
    setMsg("");
    try {
      const payload = {
        subject: profile.subject,
        subjects: profile.subject,
        experience: profile.experience,
        qualification: profile.qualification,
        bio: profile.bio,
        phone: profile.phone,
        city: profile.city,
      };
      if (role === "tutor") await profileAPI.updateTutor(payload);
      else await profileAPI.updateTeacher(payload);
      setMsg("Profile saved.");
      setEditMode(false);
      onRefresh?.();
    } catch (ex) {
      setMsg(ex.message);
    }
    setSaving(false);
  }

  return (
    <>
      <div className="flexb" style={{ marginBottom: 4 }}>
        <h1 className="portal-page-title" style={{ marginBottom: 0 }}>My Profile</h1>
        <button type="button" className="btn btn-outline btn-sm" onClick={() => setEditMode((e) => !e)}>
          {editMode ? "Cancel" : "Edit Profile"}
        </button>
      </div>
      <p className="portal-page-desc">Personal details and resume — schools see this when you apply</p>
      {msg && <div className="alert a-ok">{msg}</div>}

      <div className="portal-profile-banner">
        <Avatar name={profile.name} size={80} round />
        <div>
          <h2>{profile.name}</h2>
          <p>{profile.subject} · {profile.city}</p>
          <div className="portal-progress" style={{ maxWidth: 320, marginTop: 12 }}>
            <div className="portal-progress__bar">
              <div className="portal-progress__fill" style={{ width: `${profilePercent}%` }} />
            </div>
            <span className="portal-progress__label">
              {profilePercent}% complete — reach 70% and upload resume to apply
            </span>
          </div>
        </div>
      </div>

      <div className="grid2">
        <FormSection title="Personal Details">
          <div className="fg"><label className="flabel">Full Name</label><input className="input" value={profile.name} disabled /></div>
          <div className="fg"><label className="flabel">Email</label><input className="input" value={user.email} disabled /></div>
          <div className="fg"><label className="flabel">Mobile</label><input className="input" value={profile.phone} disabled={!editMode} onChange={(e) => setProfile((p) => ({ ...p, phone: e.target.value }))} /></div>
          <div className="fg"><label className="flabel">City</label><input className="input" value={profile.city} disabled={!editMode} onChange={(e) => setProfile((p) => ({ ...p, city: e.target.value }))} /></div>
        </FormSection>

        <FormSection title="Job Preferences">
          <div className="fg">
            <label className="flabel">{role === "tutor" ? "Subjects" : "Subject"}</label>
            {role === "tutor" ? (
              <input className="input" value={profile.subject} disabled={!editMode} onChange={(e) => setProfile((p) => ({ ...p, subject: e.target.value }))} />
            ) : (
              <select className="input" value={profile.subject} disabled={!editMode} onChange={(e) => setProfile((p) => ({ ...p, subject: e.target.value }))}>
                {SUBJECTS.map((s) => <option key={s}>{s}</option>)}
              </select>
            )}
          </div>
          <div className="fg">
            <label className="flabel">Experience</label>
            <select className="input" value={profile.experience} disabled={!editMode} onChange={(e) => setProfile((p) => ({ ...p, experience: e.target.value }))}>
              {EXPERIENCE_LEVELS.map((s) => <option key={s}>{s}</option>)}
            </select>
          </div>
          <div className="fg">
            <label className="flabel">Qualification</label>
            <select className="input" value={profile.qualification} disabled={!editMode} onChange={(e) => setProfile((p) => ({ ...p, qualification: e.target.value }))}>
              {QUALIFICATIONS.map((s) => <option key={s}>{s}</option>)}
            </select>
          </div>
        </FormSection>
      </div>

      <FormSection title="Introduction">
        <div className="fg"><label className="flabel">Short Bio</label><textarea className="input" rows={4} value={profile.bio} disabled={!editMode} onChange={(e) => setProfile((p) => ({ ...p, bio: e.target.value }))} /></div>
        {editMode && <button type="button" className="btn btn-primary" onClick={save} disabled={saving}>{saving ? "Saving..." : "Save Profile"}</button>}
      </FormSection>
    </>
  );
}
