const BASE_URL = process.env.REACT_APP_API_URL || 'https://teacher-hiring-backend.onrender.com/api';
const API_ROOT = BASE_URL.replace(/\/api$/, '');

export function getToken() {
  return localStorage.getItem('eduhire_token');
}

export function saveSession({ token, user }) {
  localStorage.setItem('eduhire_token', token);
  localStorage.setItem('eduhire_user', JSON.stringify(user));
}

export function clearSession() {
  localStorage.removeItem('eduhire_token');
  localStorage.removeItem('eduhire_user');
}

export function resumeUrl(path) {
  if (!path) return null;
  if (path.startsWith('http')) return path;
  return `${API_ROOT}${path}`;
}

function headers(auth = false, isForm = false) {
  const h = {};
  if (!isForm) h['Content-Type'] = 'application/json';
  if (auth) {
    const token = getToken();
    if (token) h.Authorization = `Bearer ${token}`;
  }
  return h;
}

async function request(method, path, body, auth = false) {
  const res = await fetch(`${BASE_URL}${path}`, {
    method,
    headers: headers(auth),
    body: body ? JSON.stringify(body) : undefined,
  });
  const data = await res.json().catch(() => ({}));
  if (!res.ok) throw new Error(data.message || 'Request failed');
  return data;
}

export const authAPI = {
  signup: (payload) => request('POST', '/auth/signup', payload),
  login: (payload) => request('POST', '/auth/login', payload),
  me: () => request('GET', '/auth/me', null, true),
};

export const profileAPI = {
  updateTeacher: (payload) => request('PUT', '/profile/teacher', payload, true),
  updateTutor: (payload) => request('PUT', '/profile/tutor', payload, true),
  updateSchool: (payload) => request('PUT', '/profile/school', payload, true),
  uploadResume: (file) => {
    const fd = new FormData();
    fd.append('resume', file);
    return fetch(`${BASE_URL}/profile/resume`, {
      method: 'POST',
      headers: headers(true, true),
      body: fd,
    }).then(async (res) => {
      const data = await res.json();
      if (!res.ok) throw new Error(data.message || 'Upload failed');
      return data;
    });
  },
};

export const jobsAPI = {
  getAll: (params = {}) => {
    const qs = new URLSearchParams(params).toString();
    return request('GET', `/jobs${qs ? `?${qs}` : ''}`);
  },
  getOne: (id) => request('GET', `/jobs/${id}`),
  post: (payload) => request('POST', '/jobs', payload, true),
  getMyJobs: () => request('GET', '/my-jobs', null, true),
};

export const applicationsAPI = {
  apply: (payload) => request('POST', '/applications', payload, true),
  myApplications: () => request('GET', '/my-applications', null, true),
  getApplicants: (jobId) => request('GET', `/job-applicants/${jobId}`, null, true),
  updateStatus: (id, status) => request('PATCH', `/applications/${id}`, { status }, true),
};

export const adminAPI = {
  stats: () => request('GET', '/admin/stats', null, true),
  pendingJobs: () => request('GET', '/admin/pending-jobs', null, true),
  reviewJob: (id, action) => request('PATCH', `/admin/jobs/${id}`, { action }, true),
  pendingSchools: () => request('GET', '/admin/pending-schools', null, true),
  reviewSchool: (userId, action, note) => request('PATCH', `/admin/schools/${userId}`, { action, note }, true),
  users: (role) => request('GET', `/admin/users${role ? `?role=${role}` : ''}`, null, true),
  schools: () => request('GET', '/admin/schools', null, true),
  teachers: () => request('GET', '/admin/teachers', null, true),
};
