import Avatar from "./Avatar";
import { IconEdit } from "./icons";

export default function PortalSidebar({
  user,
  profilePercent = 40,
  joined = "Mar 2025",
  updated = "May 2025",
  menu,
  onNavigate,
  onViewProfile,
  showReferral = true,
  referralCode = "EDU2025",
}) {
  return (
    <aside className="portal-sidebar">
      <div className="portal-profile-card">
        <Avatar name={user?.name || "User"} size={72} round />
        <h3 className="portal-profile-card__hello">Hello, {user?.name?.split(" ")[0]}</h3>
        <p className="portal-profile-card__meta">
          Joined {joined} · Updated {updated}
        </p>
        <div className="portal-progress">
          <div className="portal-progress__bar">
            <div className="portal-progress__fill" style={{ width: `${profilePercent}%` }} />
          </div>
          <span className="portal-progress__label">{profilePercent}% complete</span>
        </div>
        <button type="button" className="btn btn-primary portal-profile-card__btn" onClick={onViewProfile}>
          <IconEdit /> View Profile
        </button>
      </div>

      {showReferral && (
        <div className="portal-referral">
          <div className="portal-referral__label">Your Referral Code</div>
          <div className="portal-referral__code">{referralCode}</div>
          <button
            type="button"
            className="btn btn-outline btn-sm"
            style={{ width: "100%", marginTop: 10 }}
            onClick={() => navigator.clipboard?.writeText?.(referralCode)}
          >
            Share Code
          </button>
        </div>
      )}

      <nav className="portal-nav">
        {menu.map((item) => (
          <button
            key={item.id}
            type="button"
            className={`portal-nav__item ${item.active ? "active" : ""}`}
            onClick={() => onNavigate(item)}
          >
            <span className="portal-nav__icon">{item.icon}</span>
            <span className="portal-nav__label">{item.label}</span>
            {item.badge != null && item.badge > 0 && (
              <span className="portal-nav__badge">{item.badge}</span>
            )}
          </button>
        ))}
      </nav>
    </aside>
  );
}
