import { useAuth } from "../../context/AuthContext";

export default function Navbar({ setPage }) {
  const { user, logout } = useAuth();

  return (
    <nav className="nav">
      <div className="container flexb">
        <div className="nav-brand" onClick={() => setPage("home")}>EduHire</div>
        <div className="nav-links">
          <span className="nav-link" onClick={() => setPage("jobs")}>Jobs</span>
          <span className="nav-link" onClick={() => setPage("institutes")}>Schools / Institutes</span>
          <span className="nav-link" onClick={() => setPage("faq")}>FAQ</span>
          {user ? (
            <>
              <button className="btn btn-outline btn-sm" onClick={() => setPage("dashboard")}>Dashboard</button>
              <button className="btn btn-ghost btn-sm" onClick={logout}>Logout</button>
            </>
          ) : (
            <>
              <button className="btn btn-outline btn-sm" onClick={() => setPage("login")}>Login</button>
              <button className="btn btn-primary btn-sm" onClick={() => setPage("signup")}>Sign Up Free</button>
            </>
          )}
        </div>
      </div>
    </nav>
  );
}
