export function teacherMenu(tab) {
  return [
    { id: "overview", label: "Dashboard", icon: <IconDashboard />, active: tab === "overview" },
    { id: "profile", label: "My Profile", icon: <IconUser />, active: tab === "profile" },
    { id: "find", label: "Find Job", icon: <IconSearch />, active: false },
    { id: "saved", label: "Saved Jobs", icon: <IconBookmark />, active: tab === "saved" },
    { id: "applied", label: "Applied Jobs", icon: <IconFile />, active: tab === "applied" },
    { id: "experience", label: "Experience", icon: <IconBriefcase />, active: tab === "experience" },
    { id: "education", label: "Education", icon: <IconGraduation />, active: tab === "education" },
    { id: "interests", label: "Interests & Achievements", icon: <IconStar />, active: tab === "interests" },
    { id: "resume", label: "Resume Builder", icon: <IconResume />, active: tab === "resume" },
    { id: "security", label: "Security", icon: <IconShield />, active: tab === "security" },
  ];
}

export function schoolMenu(tab, counts = {}) {
  return [
    { id: "overview", label: "Dashboard", icon: <IconDashboard />, active: tab === "overview" },
    { id: "profile", label: "Institute Profile", icon: <IconUser />, active: tab === "profile" },
    { id: "jobs", label: "My Job Posts", icon: <IconBriefcase />, active: tab === "jobs", badge: counts.jobs },
    { id: "applications", label: "Applications", icon: <IconFile />, active: tab === "applications", badge: counts.applications },
    { id: "search", label: "Search Educators", icon: <IconSearch />, active: tab === "search" },
    { id: "admission", label: "Admission Inquiry", icon: <IconStar />, active: tab === "admission" },
    { id: "security", label: "Security", icon: <IconShield />, active: tab === "security" },
  ];
}

export function adminMenu(tab, counts = {}) {
  const pending = typeof counts === "number" ? counts : counts.pendingJobs || 0;
  const pendingSchools = counts.pendingSchools || 0;
  return [
    { id: "overview", label: "Dashboard", icon: <IconDashboard />, active: tab === "overview" },
    { id: "pending-schools", label: "Pending Institutes", icon: <IconUsers />, active: tab === "pending-schools", badge: pendingSchools },
    { id: "pending", label: "Pending Jobs", icon: <IconFile />, active: tab === "pending", badge: pending },
    { id: "jobs", label: "All Jobs", icon: <IconBriefcase />, active: tab === "jobs" },
    { id: "teachers", label: "Teachers", icon: <IconUser />, active: tab === "teachers" },
    { id: "schools", label: "Schools", icon: <IconUsers />, active: tab === "schools" },
    { id: "security", label: "Security", icon: <IconShield />, active: tab === "security" },
  ];
}
