import { useEffect, useState } from "react";
import PortalLayout from "../../components/dashboard/PortalLayout";
import DataTable from "../../components/dashboard/DataTable";
import { teacherMenu } from "../../data/portalMenus";
import TeacherOverview from "../portal/teacher/TeacherOverview";
import TeacherProfile from "../portal/teacher/TeacherProfile";
import TeacherExperience from "../portal/teacher/TeacherExperience";
import TeacherEducation from "../portal/teacher/TeacherEducation";
import TeacherInterests from "../portal/teacher/TeacherInterests";
import TeacherResume from "../portal/teacher/TeacherResume";
import TeacherSecurity from "../portal/teacher/TeacherSecurity";
import { applicationsAPI } from "../../api";

function statusBadge(status) {
  const map = { shortlisted: "bgreen", rejected: "bred", hired: "bgreen", pending: "byellow" };
  return map[status] || "byellow";
}

function timeAgo(dateStr) {
  if (!dateStr) return "—";
  const days = Math.floor((Date.now() - new Date(dateStr)) / 86400000);
  if (days < 1) return "Today";
  if (days === 1) return "1 day ago";
  return `${days} days ago`;
}

export default function TeacherDashboard({ user, setPage, onRefresh }) {
  const [tab, setTab] = useState("overview");
  const [applications, setApplications] = useState([]);
  const [editMode, setEditMode] = useState(false);
  const p = user.profile || {};
  const [profile, setProfile] = useState({
    name: user.name,
    subject: p.subject || p.subjects || "",
    city: user.city || "",
    experience: p.experience || "",
    qualification: p.qualification || "",
    phone: user.phone || "",
    bio: p.bio || "",
  });

  const profilePct = user.profileComplete || 0;
  const canApply = user.canApply;

  useEffect(() => {
    applicationsAPI.myApplications().then(setApplications).catch(() => {});
  }, []);

  function handleNav(item) {
    if (item.id === "find") setPage("jobs");
    else setTab(item.id);
  }

  const menu = teacherMenu(tab);

  return (
    <PortalLayout
      user={user}
      setPage={setPage}
      menu={menu}
      onNavigate={handleNav}
      onViewProfile={() => setTab("profile")}
      profilePercent={profilePct}
    >
      {!canApply && tab === "overview" && (
        <div className="alert a-warn" style={{ marginBottom: 16 }}>
          Complete your profile (70%+) and upload your resume to apply for jobs.
        </div>
      )}

      {tab === "overview" && (
        <TeacherOverview
          user={user}
          setPage={setPage}
          setTab={setTab}
          applications={applications.map((a) => ({
            job: a.job_title,
            school: a.institute_name,
            status: a.status,
            ago: timeAgo(a.created_at),
            color: statusBadge(a.status),
          }))}
          savedCount={0}
          profilePercent={profilePct}
        />
      )}
      {tab === "profile" && (
        <TeacherProfile
          user={user}
          profile={profile}
          setProfile={setProfile}
          editMode={editMode}
          setEditMode={setEditMode}
          profilePercent={profilePct}
          role={user.role}
          onRefresh={onRefresh}
        />
      )}
      {tab === "applied" && (
        <>
          <h1 className="portal-page-title">Applied Jobs</h1>
          <p className="portal-page-desc">Track status of all your job applications</p>
          <DataTable columns={["Job Title", "School / Institute", "Applied", "Status"]}>
            {applications.map((a) => (
              <tr key={a.id}>
                <td><strong>{a.job_title}</strong></td>
                <td style={{ color: "var(--muted)" }}>{a.institute_name}</td>
                <td>{timeAgo(a.created_at)}</td>
                <td><span className={`badge ${statusBadge(a.status)}`}>{a.status}</span></td>
              </tr>
            ))}
          </DataTable>
          {applications.length === 0 && <p style={{ color: "var(--muted)", marginTop: 16 }}>No applications yet. Browse jobs to apply.</p>}
        </>
      )}
      {tab === "saved" && (
        <>
          <h1 className="portal-page-title">Saved Jobs</h1>
          <p className="portal-page-desc">Saved jobs feature coming soon</p>
        </>
      )}
      {tab === "experience" && <TeacherExperience />}
      {tab === "education" && <TeacherEducation />}
      {tab === "interests" && <TeacherInterests />}
      {tab === "resume" && <TeacherResume user={user} onRefresh={onRefresh} />}
      {tab === "security" && <TeacherSecurity user={user} />}
    </PortalLayout>
  );
}
