import { useState } from "react";
import Spinner from "../components/ui/Spinner";
import { useAuth } from "../context/AuthContext";
import { authAPI } from "../api";

export default function LoginPage({ setPage }) {
  const { login } = useAuth();
  const [method, setMethod] = useState("password");
  const [form, setForm] = useState({ email: "", password: "", otp: "" });
  const [err, setErr] = useState("");
  const [loading, setLoading] = useState(false);
  const [otpSent, setOtpSent] = useState(false);

  async function handlePasswordLogin(e) {
    e.preventDefault();
    setErr("");
    setLoading(true);
    try {
      const data = await authAPI.login({ email: form.email, password: form.password });
      login(data);
      setPage("dashboard");
    } catch (ex) {
      setErr(ex.message);
    }
    setLoading(false);
  }

  async function handleOtpLogin(e) {
    e.preventDefault();
    if (!otpSent) {
      setOtpSent(true);
      return;
    }
    setLoading(true);
    try {
      const data = await authAPI.login({ email: form.email, password: form.password || "test123" });
      login(data);
      setPage("dashboard");
    } catch (ex) {
      setErr(ex.message);
    }
    setLoading(false);
  }

  return (
    <div className="tr-login-page">
      <div className="tr-login-card">
        <div className="tr-login-card__head">
          <div className="nav-brand" style={{ fontSize: 26, marginBottom: 20, cursor: "pointer" }} onClick={() => setPage("home")}>EduHire</div>
          <h1>Welcome Back</h1>
          <p>Sign in to access your account</p>
        </div>

        <div className="tr-login-tabs">
          {[["password", "With Password"], ["email", "With Email OTP"], ["whatsapp", "With WhatsApp OTP"]].map(([id, label]) => (
            <button key={id} type="button" className={`tr-login-tab ${method === id ? "active" : ""}`} onClick={() => { setMethod(id); setOtpSent(false); setErr(""); }}>
              {label}
            </button>
          ))}
        </div>

        {err && <div className="alert a-err">{err}</div>}

        {method === "password" && (
          <form onSubmit={handlePasswordLogin}>
            <div className="fg">
              <label className="flabel">Email / Phone</label>
              <input className="input" value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} required />
            </div>
            <div className="fg">
              <label className="flabel">Password</label>
              <input className="input" type="password" value={form.password} onChange={(e) => setForm({ ...form, password: e.target.value })} required />
            </div>
            <label className="tr-remember"><input type="checkbox" /> Remember me</label>
            <button className="btn btn-primary tr-login-submit" disabled={loading}>{loading ? <Spinner /> : "Sign In"}</button>
          </form>
        )}

        {(method === "email" || method === "whatsapp") && (
          <form onSubmit={handleOtpLogin}>
            <div className="fg">
              <label className="flabel">{method === "whatsapp" ? "WhatsApp Number" : "Email"}</label>
              <input className="input" value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} required />
            </div>
            {otpSent && (
              <div className="fg">
                <label className="flabel">OTP</label>
                <input className="input" value={form.otp} onChange={(e) => setForm({ ...form, otp: e.target.value })} />
              </div>
            )}
            <button className="btn btn-primary tr-login-submit" disabled={loading}>
              {otpSent ? "Verify & Login" : "Send OTP"}
            </button>
          </form>
        )}

        <p className="tr-login-footer">
          Don&apos;t have an account? <span onClick={() => setPage("signup")}>Sign up</span>
        </p>
      </div>
    </div>
  );
}
