import { useState } from "react";
import Spinner from "../components/ui/Spinner";
import { useAuth } from "../context/AuthContext";
import { authAPI } from "../api";
import { SUBJECTS, EXPERIENCE_LEVELS, QUALIFICATIONS, INSTITUTE_TYPES } from "../data/mockData";

const ROLES = [
  ["teacher", "Teacher"],
  ["tutor", "Tutor"],
  ["school", "School / Institute / College"],
];

export default function AuthPage({ mode, setPage }) {
  const { login } = useAuth();
  const [form, setForm] = useState({
    name: "", email: "", password: "", role: "teacher", phone: "", city: "", state: "",
    subject: "", subjects: "", experience: "", qualification: "", institute_type: "", contact_person: "",
  });
  const [step, setStep] = useState(1);
  const [err, setErr] = useState("");
  const [loading, setLoading] = useState(false);

  const up = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  async function handleSignup(e) {
    e.preventDefault();
    if (step === 1) {
      setStep(2);
      return;
    }
    setErr("");
    setLoading(true);
    try {
      const data = await authAPI.signup(form);
      login(data);
      setPage("dashboard");
    } catch (ex) {
      setErr(ex.message);
    }
    setLoading(false);
  }

  if (mode === "login") {
    setPage("login");
    return null;
  }

  return (
    <div className="auth-page">
      <div style={{ width: "100%", maxWidth: 480 }}>
        <div style={{ textAlign: "center", marginBottom: 28 }}>
          <div className="nav-brand" style={{ fontSize: 28, marginBottom: 12, cursor: "pointer" }} onClick={() => setPage("home")}>EduHire</div>
          <h1 style={{ fontSize: 26 }}>Create Account</h1>
          <p style={{ color: "var(--muted)", fontSize: 14 }}>
            {step === 1 ? "Step 1 — Basic details" : "Step 2 — Complete your profile"}
          </p>
          <div style={{ display: "flex", justifyContent: "center", gap: 8, marginTop: 14 }}>
            {[1, 2].map((s) => (
              <div key={s} style={{ width: 40, height: 4, borderRadius: 2, background: step >= s ? "var(--accent)" : "var(--border)" }} />
            ))}
          </div>
        </div>

        <div className="card auth-card">
          {err && <div className="alert a-err">{err}</div>}

          <form onSubmit={handleSignup}>
            {step === 1 ? (
              <>
                <div className="fg">
                  <label className="flabel">I am registering as</label>
                  <div style={{ display: "grid", gridTemplateColumns: "1fr", gap: 8 }}>
                    {ROLES.map(([val, label]) => (
                      <div key={val} className={`role-select ${form.role === val ? "active" : ""}`} onClick={() => up("role", val)}>
                        {label}
                      </div>
                    ))}
                  </div>
                </div>
                <div className="fg">
                  <label className="flabel">{form.role === "school" ? "Institute name" : "Full name"}</label>
                  <input className="input" value={form.name} onChange={(e) => up("name", e.target.value)} required />
                </div>
                <div className="fg">
                  <label className="flabel">Email</label>
                  <input className="input" type="email" value={form.email} onChange={(e) => up("email", e.target.value)} required />
                </div>
                <div className="grid2">
                  <div className="fg">
                    <label className="flabel">Phone</label>
                    <input className="input" value={form.phone} onChange={(e) => up("phone", e.target.value)} />
                  </div>
                  <div className="fg">
                    <label className="flabel">City</label>
                    <input className="input" value={form.city} onChange={(e) => up("city", e.target.value)} />
                  </div>
                </div>
                <div className="fg">
                  <label className="flabel">Password</label>
                  <input className="input" type="password" value={form.password} onChange={(e) => up("password", e.target.value)} required />
                </div>
              </>
            ) : form.role === "school" ? (
              <>
                <div className="alert a-warn">After completing details, your institute will wait for admin approval before you can post jobs.</div>
                <div className="fg">
                  <label className="flabel">Institute type</label>
                  <select className="input" value={form.institute_type} onChange={(e) => up("institute_type", e.target.value)}>
                    <option value="">Select</option>
                    {INSTITUTE_TYPES.map((s) => <option key={s}>{s}</option>)}
                  </select>
                </div>
                <div className="fg">
                  <label className="flabel">Contact person</label>
                  <input className="input" value={form.contact_person} onChange={(e) => up("contact_person", e.target.value)} />
                </div>
              </>
            ) : (
              <>
                <div className="alert a-ok">Teachers must upload a resume before applying to jobs.</div>
                <div className="fg">
                  <label className="flabel">{form.role === "tutor" ? "Subjects" : "Subject"}</label>
                  {form.role === "tutor" ? (
                    <input className="input" value={form.subjects} onChange={(e) => up("subjects", e.target.value)} placeholder="e.g. Math, Science" />
                  ) : (
                    <select className="input" value={form.subject} onChange={(e) => up("subject", e.target.value)}>
                      <option value="">Select</option>
                      {SUBJECTS.map((s) => <option key={s}>{s}</option>)}
                    </select>
                  )}
                </div>
                <div className="fg">
                  <label className="flabel">Experience</label>
                  <select className="input" value={form.experience} onChange={(e) => up("experience", e.target.value)}>
                    {EXPERIENCE_LEVELS.map((s) => <option key={s}>{s}</option>)}
                  </select>
                </div>
                <div className="fg">
                  <label className="flabel">Qualification</label>
                  <select className="input" value={form.qualification} onChange={(e) => up("qualification", e.target.value)}>
                    {QUALIFICATIONS.map((s) => <option key={s}>{s}</option>)}
                  </select>
                </div>
              </>
            )}
            <div style={{ display: "flex", gap: 10 }}>
              {step === 2 && <button type="button" className="btn btn-outline" style={{ flex: 1 }} onClick={() => setStep(1)}>Back</button>}
              <button className="btn btn-primary" style={{ flex: 2, padding: "13px" }} disabled={loading}>
                {loading ? <Spinner /> : step === 1 ? "Continue" : "Create Account"}
              </button>
            </div>
          </form>

          <p style={{ textAlign: "center", marginTop: 20, fontSize: 14, color: "var(--muted)" }}>
            Already registered? <span style={{ color: "var(--accent)", cursor: "pointer", fontWeight: 600 }} onClick={() => setPage("login")}>Login</span>
          </p>
        </div>
      </div>
    </div>
  );
}
