export default function JobCard({ job, onApply }) {
  const salary =
    job.salary ||
    (job.salary_min
      ? `₹${Number(job.salary_min).toLocaleString("en-IN")} – ₹${Number(job.salary_max).toLocaleString("en-IN")}`
      : "Negotiable");

  return (
    <div className="card jcard" onClick={() => onApply?.(job)}>
      <div className="flexb" style={{ marginBottom: 14 }}>
        <div className="jlogo">{job.logo || "🏫"}</div>
        <span className="badge bpurple">{job.type || job.job_type}</span>
      </div>
      <h3 style={{ fontSize: 16, fontWeight: 700, marginBottom: 6 }}>{job.title}</h3>
      <div style={{ color: "var(--accent)", fontSize: 14, fontWeight: 600, marginBottom: 12 }}>
        {job.institute || job.institute_name}
      </div>
      <div style={{ display: "flex", gap: 14, marginBottom: 14, flexWrap: "wrap", fontSize: 13, color: "var(--muted)" }}>
        <span>{job.location}</span>
        <span>·</span>
        <span>{job.experience}</span>
      </div>
      <div style={{ borderTop: "1px solid var(--border)", paddingTop: 14, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <span className="badge bgreen">{salary}</span>
        <span style={{ fontSize: 12, color: "var(--muted)" }}>
          {job.applicants || job.applicant_count || 0} applicants
        </span>
      </div>
      <div style={{ marginTop: 10, fontSize: 12, color: "var(--muted)" }}>{job.posted || "Recently"}</div>
    </div>
  );
}
