import { useState, useEffect } from "react";
import { AuthContext } from "./context/AuthContext";
import { authAPI, clearSession, getToken, saveSession } from "./api";
import Navbar from "./components/layout/Navbar";
import HomePage from "./pages/HomePage";
import JobsPage from "./pages/JobsPage";
import AuthPage from "./pages/AuthPage";
import LoginPage from "./pages/LoginPage";
import FaqPage from "./pages/FaqPage";
import InstitutesPage from "./pages/InstitutesPage";
import AdminDashboard from "./pages/dashboards/AdminDashboard";
import TeacherDashboard from "./pages/dashboards/TeacherDashboard";
import SchoolDashboard from "./pages/dashboards/SchoolDashboard";

const PORTAL_PAGES = ["dashboard", "faq", "institutes"];

export default function App() {
  const [user, setUser] = useState(() => {
    try {
      const s = localStorage.getItem("eduhire_user");
      return s ? JSON.parse(s) : null;
    } catch {
      return null;
    }
  });
  const [page, setPage] = useState("home");

  async function refreshUser() {
    try {
      const u = await authAPI.me();
      setUser(u);
      localStorage.setItem("eduhire_user", JSON.stringify(u));
    } catch {}
  }

  useEffect(() => {
    if (getToken() && user) refreshUser();
  }, []);

  function login(session) {
    saveSession(session);
    setUser(session.user);
  }

  function logout() {
    clearSession();
    setUser(null);
    setPage("home");
  }

  function DashboardRouter() {
    if (!user) {
      setTimeout(() => setPage("login"), 0);
      return null;
    }
    if (user.role === "admin") return <AdminDashboard user={user} setPage={setPage} onRefresh={refreshUser} />;
    if (user.role === "teacher" || user.role === "tutor")
      return <TeacherDashboard user={user} setPage={setPage} onRefresh={refreshUser} />;
    if (user.role === "school") return <SchoolDashboard user={user} setPage={setPage} onRefresh={refreshUser} />;
    return null;
  }

  const showPublicNav = !PORTAL_PAGES.includes(page);

  return (
    <AuthContext.Provider value={{ user, login, logout, refreshUser }}>
      {showPublicNav && <Navbar setPage={setPage} />}
      {page === "home" && <HomePage setPage={setPage} />}
      {page === "jobs" && <JobsPage setPage={setPage} />}
      {page === "about" && <HomePage setPage={setPage} />}
      {page === "institutes" && <InstitutesPage setPage={setPage} />}
      {page === "faq" && <FaqPage setPage={setPage} />}
      {page === "login" && <LoginPage setPage={setPage} />}
      {page === "signup" && <AuthPage mode="signup" setPage={setPage} />}
      {page === "dashboard" && <DashboardRouter />}
    </AuthContext.Provider>
  );
}
