import { useEffect, useState } from "react";
import Avatar from "../../components/dashboard/Avatar";
import DataTable from "../../components/dashboard/DataTable";
import EmptyState from "../../components/dashboard/EmptyState";
import MetricCard from "../../components/dashboard/MetricCard";
import PortalLayout from "../../components/dashboard/PortalLayout";
import FormSection from "../../components/portal/FormSection";
import { IconBriefcase, IconFile, IconUser } from "../../components/dashboard/icons";
import { adminMenu } from "../../data/portalMenus";
import { adminAPI, jobsAPI } from "../../api";

function fmtSalary(j) {
  if (j.salary_text) return j.salary_text;
  if (j.salary_min) return `₹${Number(j.salary_min).toLocaleString("en-IN")}+`;
  return "—";
}

export default function AdminDashboard({ user, setPage }) {
  const [tab, setTab] = useState("overview");
  const [stats, setStats] = useState(null);
  const [pending, setPending] = useState([]);
  const [pendingSchools, setPendingSchools] = useState([]);
  const [activeJobs, setActiveJobs] = useState([]);
  const [teachers, setTeachers] = useState([]);
  const [schools, setSchools] = useState([]);
  const [toast, setToast] = useState("");

  const showToast = (m) => { setToast(m); setTimeout(() => setToast(""), 3000); };

  async function load() {
    try {
      const [s, pj, ps, t, sc, jobs] = await Promise.all([
        adminAPI.stats(),
        adminAPI.pendingJobs(),
        adminAPI.pendingSchools(),
        adminAPI.teachers(),
        adminAPI.schools(),
        jobsAPI.getAll(),
      ]);
      setStats(s);
      setPending(pj);
      setPendingSchools(ps);
      setTeachers(t);
      setSchools(sc);
      setActiveJobs(jobs);
    } catch {}
  }

  useEffect(() => { load(); }, []);

  async function approveJob(job) {
    try {
      await adminAPI.reviewJob(job.id, "approve");
      showToast("Job approved and published.");
      load();
    } catch (ex) { showToast(ex.message); }
  }

  async function rejectJob(id) {
    try {
      await adminAPI.reviewJob(id, "reject");
      showToast("Job rejected.");
      load();
    } catch (ex) { showToast(ex.message); }
  }

  async function reviewSchool(userId, action) {
    try {
      await adminAPI.reviewSchool(userId, action);
      showToast(action === "approve" ? "Institute approved." : "Institute rejected.");
      load();
    } catch (ex) { showToast(ex.message); }
  }

  const menu = adminMenu(tab, {
    pendingJobs: pending.length,
    pendingSchools: pendingSchools.length,
  });

  return (
    <PortalLayout
      user={user}
      setPage={setPage}
      menu={menu}
      onNavigate={(m) => setTab(m.id)}
      onViewProfile={() => setTab("overview")}
      profilePercent={100}
      toast={toast}
      showReferral={false}
    >
      {tab === "overview" && (
        <>
          <h1 className="portal-page-title">Dashboard</h1>
          <div className="metric-row">
            <MetricCard label="Teachers & Tutors" value={stats?.teachers ?? "—"} variant="blue" icon={<IconUser />} />
            <MetricCard label="Institutes" value={stats?.schools ?? "—"} variant="navy" icon={<IconBriefcase />} />
            <MetricCard label="Active Jobs" value={stats?.activeJobs ?? "—"} variant="green" icon={<IconFile />} />
            <MetricCard label="Pending Review" value={(stats?.pendingJobs || 0) + (stats?.pendingSchools || 0)} variant="orange" icon={<IconFile />} />
          </div>
          <div className="portal-widgets">
            <div className="portal-widgets__left">
              <div className="widget-card">
                <div className="widget-card__head">
                  <h2 className="widget-card__title">Pending Job Approvals</h2>
                  <button type="button" className="widget-card__link" onClick={() => setTab("pending")}>View all</button>
                </div>
                {pending.length === 0 ? <p className="widget-empty__text">No pending jobs.</p> : pending.slice(0, 5).map((job, i) => (
                  <div key={job.id} className="app-list__item" style={{ borderBottom: i < Math.min(pending.length, 5) - 1 ? "1px solid var(--border)" : "none" }}>
                    <div><div className="app-list__title">{job.title}</div><div className="app-list__meta">{job.institute_name}</div></div>
                    <div className="table-actions">
                      <button type="button" className="btn btn-success btn-sm" onClick={() => approveJob(job)}>Approve</button>
                      <button type="button" className="btn btn-danger btn-sm" onClick={() => rejectJob(job.id)}>Reject</button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
            <div className="portal-widgets__right">
              <div className="widget-card">
                <div className="widget-card__head">
                  <h2 className="widget-card__title">Pending Institutes</h2>
                  <button type="button" className="widget-card__link" onClick={() => setTab("pending-schools")}>View all</button>
                </div>
                {pendingSchools.length === 0 ? <p className="widget-empty__text">No pending institutes.</p> : pendingSchools.slice(0, 3).map((s, i) => (
                  <div key={s.user_id} className="app-list__item" style={{ borderBottom: i < 2 ? "1px solid var(--border)" : "none" }}>
                    <div><div className="app-list__title">{s.institute_name || s.name}</div><div className="app-list__meta">{s.city} · {s.institute_type}</div></div>
                    <button type="button" className="btn btn-success btn-sm" onClick={() => reviewSchool(s.user_id, "approve")}>Approve</button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </>
      )}

      {tab === "pending-schools" && (
        <>
          <h1 className="portal-page-title">Pending Institute Approvals</h1>
          <p className="portal-page-desc">Schools must be approved before they can post jobs</p>
          {pendingSchools.length === 0 ? <EmptyState title="All caught up" message="No institutes awaiting approval." /> : (
            <DataTable columns={["Institute", "Type", "Contact", "City", "Actions"]}>
              {pendingSchools.map((s) => (
                <tr key={s.user_id}>
                  <td><div className="table-cell-user"><Avatar name={s.institute_name || s.name} size={36} round /><strong>{s.institute_name || s.name}</strong></div></td>
                  <td>{s.institute_type || "—"}</td>
                  <td>{s.contact_person || s.email}</td>
                  <td>{s.city || "—"}</td>
                  <td>
                    <div className="table-actions">
                      <button type="button" className="btn btn-success btn-sm" onClick={() => reviewSchool(s.user_id, "approve")}>Approve</button>
                      <button type="button" className="btn btn-danger btn-sm" onClick={() => reviewSchool(s.user_id, "reject")}>Reject</button>
                    </div>
                  </td>
                </tr>
              ))}
            </DataTable>
          )}
        </>
      )}

      {tab === "pending" && (
        <>
          <h1 className="portal-page-title">Pending Job Approvals</h1>
          {pending.length === 0 ? <EmptyState title="All caught up" message="No pending approvals." /> : (
            <DataTable columns={["Job", "Institute", "Location", "Salary", "Actions"]}>
              {pending.map((job) => (
                <tr key={job.id}>
                  <td><div className="table-cell-user"><Avatar name={job.institute_name} size={36} round /><strong>{job.title}</strong></div></td>
                  <td>{job.institute_name}</td>
                  <td>{job.location || "—"}</td>
                  <td>{fmtSalary(job)}</td>
                  <td><div className="table-actions"><button type="button" className="btn btn-success btn-sm" onClick={() => approveJob(job)}>Approve</button><button type="button" className="btn btn-danger btn-sm" onClick={() => rejectJob(job.id)}>Reject</button></div></td>
                </tr>
              ))}
            </DataTable>
          )}
        </>
      )}

      {tab === "jobs" && (
        <>
          <h1 className="portal-page-title">All Active Jobs</h1>
          <DataTable columns={["Title", "Institute", "Location", "Type", "Applicants", "Status"]}>
            {activeJobs.map((j) => (
              <tr key={j.id}>
                <td><strong>{j.title}</strong></td>
                <td>{j.institute_name}</td>
                <td>{j.location || "—"}</td>
                <td><span className="badge bpurple">{j.job_type}</span></td>
                <td>{j.applicant_count || 0}</td>
                <td><span className="badge bgreen">Live</span></td>
              </tr>
            ))}
          </DataTable>
        </>
      )}

      {tab === "teachers" && (
        <>
          <h1 className="portal-page-title">Registered Teachers</h1>
          <DataTable columns={["Name", "Subject", "Experience", "City", "Resume"]}>
            {teachers.map((t) => (
              <tr key={t.id}>
                <td><div className="table-cell-user"><Avatar name={t.name} size={36} round /><strong>{t.name}</strong></div></td>
                <td>{t.subject || "—"}</td>
                <td>{t.experience || "—"}</td>
                <td>{t.city || "—"}</td>
                <td><span className={`badge ${t.resume_url ? "bgreen" : "byellow"}`}>{t.resume_url ? "Uploaded" : "Missing"}</span></td>
              </tr>
            ))}
          </DataTable>
        </>
      )}

      {tab === "schools" && (
        <>
          <h1 className="portal-page-title">Registered Institutes</h1>
          <DataTable columns={["Institute", "Type", "City", "Approval", "Contact"]}>
            {schools.map((s) => (
              <tr key={s.id}>
                <td><div className="table-cell-user"><Avatar name={s.institute_name || s.name} size={36} round /><strong>{s.institute_name || s.name}</strong></div></td>
                <td>{s.institute_type || "—"}</td>
                <td>{s.city || "—"}</td>
                <td><span className={`badge ${s.approval_status === "approved" ? "bgreen" : s.approval_status === "rejected" ? "bred" : "byellow"}`}>{s.approval_status}</span></td>
                <td>{s.contact_person || s.email}</td>
              </tr>
            ))}
          </DataTable>
        </>
      )}

      {tab === "security" && (
        <>
          <h1 className="portal-page-title">Security</h1>
          <FormSection title="Admin Account">
            <div className="fg"><label className="flabel">Email</label><input className="input" value={user?.email || ""} disabled /></div>
          </FormSection>
        </>
      )}
    </PortalLayout>
  );
}
