import { useState } from "react";
import FormSection from "../../../components/portal/FormSection";
import Spinner from "../../../components/ui/Spinner";
import { profileAPI, resumeUrl } from "../../../api";

export default function TeacherResume({ user, onRefresh }) {
  const [uploading, setUploading] = useState(false);
  const [msg, setMsg] = useState("");
  const resume = user.profile?.resume_url;

  async function handleUpload(e) {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploading(true);
    setMsg("");
    try {
      const data = await profileAPI.uploadResume(file);
      setMsg(data.message || "Resume uploaded.");
      onRefresh?.();
    } catch (ex) {
      setMsg(ex.message);
    }
    setUploading(false);
  }

  return (
    <>
      <h1 className="portal-page-title">Resume</h1>
      <p className="portal-page-desc">Upload your resume (PDF, DOC, DOCX) — required before applying to jobs</p>
      {msg && <div className={`alert ${msg.includes("uploaded") ? "a-ok" : "a-err"}`}>{msg}</div>}
      <FormSection title="Upload Resume">
        {resume ? (
          <div className="alert a-ok" style={{ marginBottom: 16 }}>
            Resume on file. <a href={resumeUrl(resume)} target="_blank" rel="noreferrer">View current resume</a>
          </div>
        ) : (
          <div className="alert a-warn" style={{ marginBottom: 16 }}>No resume uploaded yet. You cannot apply until you upload one.</div>
        )}
        <div className="fg">
          <label className="flabel">Select file (max 5MB)</label>
          <input className="input" type="file" accept=".pdf,.doc,.docx" onChange={handleUpload} disabled={uploading} />
        </div>
        {uploading && <Spinner />}
      </FormSection>
    </>
  );
}
